function Invoke-GitChecked {
  & git @args
  if ($LASTEXITCODE -ne 0) { throw "git $($args -join ' ') failed" }
}

function Invoke-GitNewBranch {
  $rawBranchName = @'
{{branch_name}}
'@
  $branchName = $rawBranchName.Trim()
  if ([string]::IsNullOrWhiteSpace($branchName)) { throw "Branch name is required." }
  if ($branchName.Contains("`n") -or $branchName.Contains("`r")) { throw "Branch name must be a single line." }
  if ($branchName.StartsWith("-")) { throw "Branch name must not start with '-'." }

  & git rev-parse --git-dir *> $null
  if ($LASTEXITCODE -ne 0) { throw "Not in a Git repository." }

  $validatedBranchName = & git check-ref-format --branch $branchName
  if ($LASTEXITCODE -ne 0) { throw "Invalid branch name: $branchName" }
  $validatedBranchName = ($validatedBranchName -join "").Trim()
  if ($validatedBranchName -ne $branchName) { throw "Branch name must be explicit and unambiguous." }

  & git show-ref --verify --quiet "refs/heads/$branchName"
  if ($LASTEXITCODE -eq 0) { throw "Branch '$branchName' already exists." }
  if ($LASTEXITCODE -ne 1) { throw "git show-ref failed" }

  Invoke-GitChecked switch -c $branchName
  Invoke-GitChecked status --short
}

Invoke-GitNewBranch
